const geminiResp = $input.first().json;
const text = geminiResp.candidates?.[0]?.content?.parts?.[0]?.text || 'Ошибка';
const lead = $('Extract lead data').first().json;

// Simple scoring: if niche mentioned, score up
let score = 50;
if (lead.niche && lead.niche !== '—') score += 15;
if (lead.source === 'ads') score += 10;

return [{ json: { qualify_script: text, lead_name: lead.name, lead_contact: lead.contact, lead_niche: lead.niche, initial_score: score } }];

